UPDATE COMMUNITY_COMMENT
SET
    CONTENT    = #{content},
    UPDATED_AT = NOW(),
    UPDATED_BY = #{userId}
WHERE COMMENT_ID = #{commentId}
  AND USER_ID    = #{userId}
  AND DELETED_YN = 'N'

UPDATE COMMUNITY_COMMENT
SET
    CONTENT    = '삭제된 댓글입니다.',
    DELETED_YN = 'Y',
    UPDATED_AT = NOW(),
    UPDATED_BY = #{userId}
WHERE COMMENT_ID = #{commentId}
  AND USER_ID    = #{userId}
  AND DELETED_YN = 'N'

UPDATE COMMUNITY_COMMENT
SET
    GROUP_ID   = #{groupId},
    UPDATED_AT = NOW(),
    UPDATED_BY = #{userId}
WHERE COMMENT_ID = #{commentId}

